//! Reference test vectors for ARM Hardware Key Attestation.
//!
//! All certificate strings below are reused verbatim from
//! Acurast/acurast-substrate@d205a7d3, file
//! `pallets/acurast/common/src/attestation.rs`. They are real attestation
//! chains captured from production Android devices:
//!
//! - `SAMSUNG_*`: a Samsung TEE-rooted (TrustZone, not StrongBox) chain
//!   captured from a Samsung Galaxy S22 with attestation_version=100
//!   (KeyMint v1).
//! - `PIXEL_*`: a Google Pixel StrongBox-rooted chain (Titan-M security
//!   chip), with attestation_version=4 (Keymaster v4).
//! - `*_INVALID`: the corresponding chain with the leaf signature byte
//!   tampered with — used as a negative test.
//! - `PIXEL_ROOT_CERT_UNTRUSTED`: same Pixel root cert with a single trailing
//!   byte flipped — confirms the trust-root pinning works.
//!
//! License-wise these strings are public-domain test material (they came
//! from real device attestations, but the key pairs they were issued to
//! belong to test devices held by the Acurast team and the chains are
//! published openly in their MIT/Unlicense-licensed test code).

#![cfg(test)]

pub const SAMSUNG_ROOT_CERT: &str = "";

pub const SAMSUNG_KEY_CERT: &str = "";

pub const SAMSUNG_INTERMEDIATE_1_CERT: &str = "";

pub const SAMSUNG_INTERMEDIATE_2_CERT: &str = "";

pub const PIXEL_ROOT_CERT: &str = "";

pub const PIXEL_INTERMEDIATE_2_CERT: &str = "";

pub const PIXEL_INTERMEDIATE_1_CERT: &str = "";

pub const PIXEL_KEY_CERT: &str = "";

/// Pixel leaf cert with the LAST byte of the signature flipped from 'Z' (0x5A) to
/// 'Y' (0x59). The signature byte tampering breaks ECDSA validation in the
/// last cert; the chain MUST therefore fail.
pub const PIXEL_KEY_CERT_INVALID: &str = "";

/// Pixel root cert with the trailing byte (the last char of the signature)
/// flipped — the cert is now self-inconsistent + isn't in our pinned trust
/// roots, so the chain MUST fail.
pub const PIXEL_ROOT_CERT_UNTRUSTED: &str = "";
